import React from 'react'
import { graphql, Link } from 'gatsby'
import Img from 'gatsby-image'

import SEO from '../components/seo'
import Layout from '../components/layout'

const Blog = ({ data }) => {
  const { edges } = data.allMarkdownRemark

  return (
    <Layout>
      <SEO title="Blog" />
      <div className="h-full flex flex-col items-center justify-start sm:flex-row sm:items-start">
        {edges.map(({ node }) => (
          <div
            className="bg-white max-w-img m-2 rounded shadow-xl hover:shadow-inner"
            key={node.id}
          >
            <Link to={node.fields.slug}>
              <Img
                fixed={node.frontmatter.coverImage.childImageSharp.fixed}
                className="rounded"
                alt="Cover Image"
              />
              <div className="px-4 py-6">
                <div className="mb-2 font-bold text-lg text-center">
                  {node.frontmatter.title}
                </div>
                <p className="text-gray-700 text-base text-justify">
                  {node.excerpt}
                </p>
              </div>
            </Link>

            <div className="flex flex-wrap content-center justify-end px-4 py-6">
              {node.frontmatter.tags.map((item, index) => (
                <span
                  key={`${node.id}+${index}`}
                  className="cursor-pointer inline-block bg-gray-200 rounded-full px-3 py-1 text-sm font-semibold text-gray-700 mr-2"
                >
                  {item}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>
    </Layout>
  )
}

export default Blog

// default query to populate list
export const query = graphql`
  query {
    allMarkdownRemark(
      sort: { fields: [frontmatter___date], order: DESC }
      filter: {
        frontmatter: { draft: { ne: true } }
        fileAbsolutePath: { regex: "/content/" }
      }
    ) {
      totalCount
      edges {
        node {
          excerpt
          id
          fields {
            slug
          }
          frontmatter {
            title
            date(formatString: "MMMM DD, YYYY")
            tags
            coverImage {
              childImageSharp {
                fixed(width: 300) {
                  ...GatsbyImageSharpFixed
                }
              }
            }
          }
        }
      }
    }
  }
`
